commands.cmd:
if command -v apt-mark >/dev/null 2>&1; then
  raw=$(apt-mark showhold 2>/dev/null) \
    || { echo "apt-mark showhold failed" >&2; exit 1; }
elif command -v dnf >/dev/null 2>&1; then
  raw=$(dnf versionlock list 2>/dev/null) \
    || { echo "dnf versionlock list failed" >&2; exit 1; }
else
  echo "no package manager (apt-mark/dnf) found" >&2
  exit 1
fi
printf '%s\n' "$raw" | awk '
  function esc(s){ gsub(/\\/,"\\\\",s); gsub(/"/,"\\\"",s); return s }
  BEGIN{ printf "{\"results\":["; sep="" }
  NF == 1 && $1 !~ /^#/ {
    printf "%s{\"package\":\"%s\"}", sep, esc($1)
    sep=","
  }
  END{ printf "]}" }
'
